using UnityEditor; using UnityEngine; using System.Collections.Generic; using Assets.HeroEditor4D.Common.Scripts.Enums; public class SetupPlayerModules { [MenuItem("DATN/Setup Player Modules")] public static void Execute() { var path = "Assets/Project/Resources/Data/Entities/Characters/PlayerEntityData.asset"; var data = AssetDatabase.LoadAssetAtPath<EntityData>(path); if (data == null) { Debug.LogError("PlayerEntityData not found!"); return; } data.modules = new List<IModuleData>(); data.modules.Add(new InventoryModule { inventoryType = InventoryType.Hotbar, size = 10 }); data.modules.Add(new InventoryModule { inventoryType = InventoryType.Backpack, size = 30 }); data.modules.Add(new EquipmentModule { supportedParts = new List<EquipmentPart> { EquipmentPart.Armor, EquipmentPart.Helmet, EquipmentPart.MeleeWeapon1H, EquipmentPart.MeleeWeapon2H, EquipmentPart.Shield, EquipmentPart.Bow, EquipmentPart.Wings, EquipmentPart.Vest, EquipmentPart.Leggings, EquipmentPart.Bracers } }); data.modules.Add(new AppearanceModule()); data.modules.Add(new QuestLogModule()); data.modules.Add(new HealthModule { canTakeDamage = true }); data.modules.Add(new RespawnModule()); EditorUtility.SetDirty(data); AssetDatabase.SaveAssets(); Debug.Log("Successfully setup Player modules!"); } }
